def find_pair(arr, target):
    left = 0
    right = len(arr) - 1

    while left < right:
        current_sum = arr[left] + arr[right]
        if current_sum == target:
            return (arr[left], arr[right])
        elif current_sum < target:
            left += 1
        else:
            right -= 1

    return "Pair not found"

arr = [1, 2, 3, 4, 5]
target = 7
print(find_pair(arr, target))  # Output: (2, 5)
